446	/**
447	 * Get the effective cron jobs list.
448	 * If `config.cronJobs` is populated (new format), use it directly.
449	 * Otherwise, fall back to legacy migration from [scheduler] + [[scheduled_skills]].
450	 */
451	export function migrateToCronJobs(config: RemiConfig): CronJobConfig[] {
452	  if (config.cronJobs.length > 0) {
453	    return config.cronJobs;
454	  }
455	
456	  // Legacy fallback — auto-migrate from old format
457	  return _legacyToCronJobs(config);
458	}
459	
460	function _legacyToCronJobs(config: RemiConfig): CronJobConfig[] {
461	  const jobs: CronJobConfig[] = [];
462	  const compactHour = parseCronHourFromExpr(config.scheduler.memoryCompactCron);
463	
464	  jobs.push(
465	    { id: "builtin:heartbeat", name: "Heartbeat", handler: "builtin:heartbeat", every: `${config.scheduler.heartbeatInterval}s` },
466	    { id: "builtin:compaction", name: "Memory Compaction", handler: "builtin:compaction", cron: config.scheduler.memoryCompactCron },
467	    { id: "builtin:cleanup", name: "Cleanup", handler: "builtin:cleanup", cron: `1 ${compactHour} * * *` },
468	  );
469	
470	  for (const skill of config.scheduledSkills) {
471	    if (!skill.name) continue;
472	    jobs.push({
473	      id: `skill:${skill.name}:gen`, name: `${skill.name} (generate)`,
474	      handler: "skill:gen", enabled: skill.enabled,
475	      cron: `0 ${skill.generateHour} * * *`,
476	      handlerConfig: { skillName: skill.name, outputDir: skill.outputDir },
477	    });
478	    jobs.push({
479	      id: `skill:${skill.name}:push`, name: `${skill.name} (push)`,
480	      handler: "skill:push", enabled: skill.enabled,
481	      cron: `${skill.pushMinute} ${skill.pushHour} * * *`,
482	      handlerConfig: {
483	        skillName: skill.name, outputDir: skill.outputDir,
484	        connectorName: skill.connectorName, pushTargets: skill.pushTargets,
485	        maxPushLength: skill.maxPushLength,
486	      },
487	    });
488	  }
489	
490	  return jobs;
491	}
