551	/**
552	 * Locate the remi.toml config file.
553	 */
554	export function findConfigPath(): string | null {
555	  const candidates = [
556	    join(process.cwd(), CONFIG_FILENAME),
557	    join(homedir(), ".remi", CONFIG_FILENAME),
558	  ];
559	  for (const c of candidates) {
560	    if (existsSync(c)) return c;
561	  }
562	  return null;
563	}
