631	function parseBotMenuItem(item: Record<string, unknown>): BotMenuItemConfig {
632	  const behaviors = (item.behaviors as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuBehavior);
633	  const children = (item.children as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuItem);
634	  const icon = item.icon ? parseBotMenuIcon(item.icon as Record<string, unknown>) : undefined;
635	
636	  return {
637	    name: (item.name as string) ?? "",
638	    i18nName: (item.i18n_name as Record<string, string>) ?? undefined,
639	    icon,
640	    tag: (item.tag as string) ?? undefined,
641	    behaviors,
642	    children,
643	  };
644	}
645	
646	function parseBotMenuConfig(data: Record<string, unknown>): BotMenuConfig {
647	  const defaultItems = (data.default as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuItem);
648	  const usersData = data.users as Array<Record<string, unknown>> | undefined;
649	
650	  const users = usersData?.map((u) => ({
651	    userId: (u.user_id as string) ?? "",
652	    userIdType: (u.user_id_type as BotMenuUserConfig["userIdType"]) ?? "open_id",
653	    label: (u.label as string) ?? undefined,
654	    items: ((u.items as Array<Record<string, unknown>>) ?? []).map(parseBotMenuItem),
655	  }));
656	
657	  return { default: defaultItems, users };
658	}
