466	    { id: "builtin:compaction", name: "Memory Compaction", handler: "builtin:compaction", cron: config.scheduler.memoryCompactCron },
467	    { id: "builtin:cleanup", name: "Cleanup", handler: "builtin:cleanup", cron: `1 ${compactHour} * * *` },
