469	
470	  for (const skill of config.scheduledSkills) {
471	    if (!skill.name) continue;
472	    jobs.push({
473	      id: `skill:${skill.name}:gen`, name: `${skill.name} (generate)`,
474	      handler: "skill:gen", enabled: skill.enabled,
475	      cron: `0 ${skill.generateHour} * * *`,
476	      handlerConfig: { skillName: skill.name, outputDir: skill.outputDir },
477	    });
478	    jobs.push({
479	      id: `skill:${skill.name}:push`, name: `${skill.name} (push)`,
480	      handler: "skill:push", enabled: skill.enabled,
481	      cron: `${skill.pushMinute} ${skill.pushHour} * * *`,
482	      handlerConfig: {
483	        skillName: skill.name, outputDir: skill.outputDir,
484	        connectorName: skill.connectorName, pushTargets: skill.pushTargets,
485	        maxPushLength: skill.maxPushLength,
486	      },
487	    });
488	  }
489	
490	  return jobs;
491	}
492	
493	/**
494	 * Write-through migration: rewrite remi.toml from old format to new [[cron.jobs]].
495	 *
496	 * - Detects if old [scheduler] or [[scheduled_skills]] sections exist
497	 * - Converts them to [[cron.jobs]]
498	 * - Removes old sections from the file
499	 * - Backs up the original as remi.toml.bak
500	 *
501	 * Returns true if migration was performed, false if already migrated or no file found.
502	 */
503	export function migrateConfigFile(configPath?: string): boolean {
504	  const filePath = configPath ?? findConfigPath();
505	  if (!filePath) return false;
506	
507	  const raw = readFileSync(filePath, "utf-8");
508	
509	  // Check if already migrated: has [[cron.jobs]] and no [scheduler] or [[scheduled_skills]]
510	  const hasCronJobs = /^\[\[cron\.jobs\]\]/m.test(raw);
511	  const hasScheduler = /^\[scheduler\]/m.test(raw);
512	  const hasScheduledSkills = /^\[\[scheduled_skills\]\]/m.test(raw);
513	
514	  if (hasCronJobs && !hasScheduler && !hasScheduledSkills) {
515	    return false; // Already migrated
516	  }
517	
518	  if (!hasScheduler && !hasScheduledSkills) {
519	    return false; // Nothing to migrate
520	  }
521	
522	  // Parse the old config to get migration data
523	  const config = loadConfig(filePath);
524	  const cronJobs = _legacyToCronJobs(config);
525	
526	  // Backup original
527	  const bakPath = filePath + ".bak";
528	  copyFileSync(filePath, bakPath);
529	
530	  // Remove old sections from raw text and append new [[cron.jobs]]
531	  let newRaw = raw;
532	
533	  // Remove [scheduler] section (header + all subsequent lines until next section header)
534	  newRaw = newRaw.replace(/^\[scheduler\]\r?\n(?:(?!\[)[^\r\n]*\r?\n?)*/gm, "");
535	
536	  // Remove all [[scheduled_skills]] blocks (header + all subsequent lines until next section header)
537	  newRaw = newRaw.replace(/^\[\[scheduled_skills\]\]\r?\n(?:(?!\[)[^\r\n]*\r?\n?)*/gm, "");
538	
539	  // Clean up excessive blank lines
540	  newRaw = newRaw.replace(/\n{3,}/g, "\n\n").trimEnd();
541	
542	  // Build [[cron.jobs]] TOML text
543	  const cronText = buildCronJobsToml(cronJobs);
544	
545	  newRaw += "\n\n# ── Cron Jobs (migrated from [scheduler] + [[scheduled_skills]]) ──\n\n" + cronText;
546	
547	  writeFileSync(filePath, newRaw, "utf-8");
548	  return true;
549	}
550	
551	/**
552	 * Locate the remi.toml config file.
553	 */
554	export function findConfigPath(): string | null {
555	  const candidates = [
556	    join(process.cwd(), CONFIG_FILENAME),
557	    join(homedir(), ".remi", CONFIG_FILENAME),
558	  ];
559	  for (const c of candidates) {
560	    if (existsSync(c)) return c;
561	  }
562	  return null;
563	}
564	
565	/**
566	 * Build TOML text for [[cron.jobs]] entries.
567	 */
568	function buildCronJobsToml(jobs: CronJobConfig[]): string {
569	  const lines: string[] = [];
570	
571	  for (const job of jobs) {
572	    lines.push("[[cron.jobs]]");
573	    lines.push(`id = ${tomlStr(job.id)}`);
574	    if (job.name) lines.push(`name = ${tomlStr(job.name)}`);
575	    lines.push(`handler = ${tomlStr(job.handler)}`);
576	    if (job.enabled === false) lines.push(`enabled = false`);
577	    if (job.cron) lines.push(`cron = ${tomlStr(job.cron)}`);
578	    if (job.tz) lines.push(`tz = ${tomlStr(job.tz)}`);
579	    if (job.every) lines.push(`every = ${tomlStr(String(job.every))}`);
580	    if (job.at) lines.push(`at = ${tomlStr(job.at)}`);
581	    if (job.timeoutMs) lines.push(`timeout_ms = ${job.timeoutMs}`);
582	    if (job.deleteAfterRun) lines.push(`delete_after_run = true`);
583	
584	    // handler_config as a sub-table
585	    if (job.handlerConfig && Object.keys(job.handlerConfig).length > 0) {
586	      lines.push("");
587	      lines.push("[cron.jobs.handler_config]");
588	      for (const [k, v] of Object.entries(job.handlerConfig)) {
589	        const key = k; // Keep camelCase keys as-is to match handler expectations
590	        if (typeof v === "string") {
591	          lines.push(`${key} = ${tomlStr(v)}`);
592	        } else if (typeof v === "number") {
593	          lines.push(`${key} = ${v}`);
594	        } else if (typeof v === "boolean") {
595	          lines.push(`${key} = ${v}`);
596	        } else if (Array.isArray(v)) {
597	          lines.push(`${key} = [${v.map((s) => tomlStr(String(s))).join(", ")}]`);
598	        }
599	      }
600	    }
601	
602	    lines.push("");
603	  }
604	
605	  return lines.join("\n");
606	}
607	
608	function tomlStr(s: string): string {
609	  return `"${s.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
610	}
611	
612	// ── Bot Menu TOML parsing ────────────────────────────────────
613	
614	function parseBotMenuBehavior(b: Record<string, unknown>): BotMenuBehavior {
615	  return {
616	    type: (b.type as BotMenuBehavior["type"]) ?? "send_message",
617	    url: (b.url as string) ?? undefined,
618	    eventKey: (b.event_key as string) ?? undefined,
619	    isPrimary: (b.is_primary as boolean) ?? undefined,
620	  };
621	}
622	
623	function parseBotMenuIcon(icon: Record<string, unknown>): BotMenuIcon {
624	  return {
625	    token: (icon.token as string) ?? undefined,
626	    color: (icon.color as string) ?? undefined,
627	    fileKey: (icon.file_key as string) ?? undefined,
628	  };
629	}
630	
631	function parseBotMenuItem(item: Record<string, unknown>): BotMenuItemConfig {
632	  const behaviors = (item.behaviors as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuBehavior);
633	  const children = (item.children as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuItem);
634	  const icon = item.icon ? parseBotMenuIcon(item.icon as Record<string, unknown>) : undefined;
635	
636	  return {
637	    name: (item.name as string) ?? "",
638	    i18nName: (item.i18n_name as Record<string, string>) ?? undefined,
639	    icon,
640	    tag: (item.tag as string) ?? undefined,
641	    behaviors,
642	    children,
643	  };
644	}
645	
646	function parseBotMenuConfig(data: Record<string, unknown>): BotMenuConfig {
647	  const defaultItems = (data.default as Array<Record<string, unknown>> | undefined)?.map(parseBotMenuItem);
648	  const usersData = data.users as Array<Record<string, unknown>> | undefined;
649	
650	  const users = usersData?.map((u) => ({
651	    userId: (u.user_id as string) ?? "",
652	    userIdType: (u.user_id_type as BotMenuUserConfig["userIdType"]) ?? "open_id",
653	    label: (u.label as string) ?? undefined,
654	    items: ((u.items as Array<Record<string, unknown>>) ?? []).map(parseBotMenuItem),
655	  }));
656	
657	  return { default: defaultItems, users };
658	}
659	
660	function parseCronHourFromExpr(cronExpr: string): number {
661	  const parts = cronExpr.split(" ");
662	  if (parts.length >= 2) {
663	    const hour = parseInt(parts[1], 10);
664	    if (!isNaN(hour)) return hour;
665	  }
666	  return 3;
667	}
668	

