import { describe, it, expect, beforeEach, afterEach } from "bun:test";
import { mkdirSync, writeFileSync, rmSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";
import { loadConfig } from "../src/config.js";

function makeTmpDir(): string {
  const dir = join(tmpdir(), `remi-test-config-${Date.now()}-${Math.random().toString(36).slice(2)}`);
  mkdirSync(dir, { recursive: true });
  return dir;
}

describe("Config", () => {
  let tmpDir: string;
  const savedEnv: Record<string, string | undefined> = {};
  const envKeys = ["REMI_PROVIDER", "REMI_FALLBACK", "REMI_MODEL", "REMI_TIMEOUT"];

  beforeEach(() => {
    tmpDir = makeTmpDir();
    // Save and clear env vars
    for (const key of envKeys) {
      savedEnv[key] = process.env[key];
      delete process.env[key];
    }
  });

  afterEach(() => {
    rmSync(tmpDir, { recursive: true, force: true });
    // Restore env vars
    for (const key of envKeys) {
      if (savedEnv[key] !== undefined) {
        process.env[key] = savedEnv[key];
      } else {
        delete process.env[key];
      }
    }
  });

  it("loads defaults", () => {
    const config = loadConfig(join(tmpDir, "nonexistent.toml"));
    expect(config.provider.name).toBe("claude_cli");
    expect(config.provider.timeout).toBe(300);
    expect(config.memoryDir).toContain("memory");
  });

  it("respects env overrides", () => {
    process.env.REMI_PROVIDER = "claude_sdk";
    process.env.REMI_TIMEOUT = "60";

    const config = loadConfig(join(tmpDir, "nonexistent.toml"));
    expect(config.provider.name).toBe("claude_sdk");
    expect(config.provider.timeout).toBe(60);
  });

  it("reads toml file", () => {
    const tomlPath = join(tmpDir, "remi.toml");
    writeFileSync(
      tomlPath,
      `
[provider]
name = "claude_sdk"
timeout = 120

[feishu]
app_id = "test-app"
port = 8080
`,
    );

    const config = loadConfig(tomlPath);
    expect(config.provider.name).toBe("claude_sdk");
    expect(config.provider.timeout).toBe(120);
    expect(config.feishu.appId).toBe("test-app");
    expect(config.feishu.port).toBe(8080);
  });

  it("env overrides toml", () => {
    process.env.REMI_PROVIDER = "codex_sdk";

    const tomlPath = join(tmpDir, "remi.toml");
    writeFileSync(
      tomlPath,
      `
[provider]
name = "claude_sdk"
`,
    );

    const config = loadConfig(tomlPath);
    expect(config.provider.name).toBe("codex_sdk"); // env wins
  });
});

import type { Hono } from "hono";
import type { RemiData } from "../remi-data.js";

export function registerConfigHandlers(app: Hono, data: RemiData) {
  app.get("/api/v1/config", (c) => {
    return c.json(data.readConfig());
  });

  app.put("/api/v1/config", async (c) => {
    const body = await c.req.json();
    const ok = data.updateConfig(body);
    if (!ok) return c.json({ error: "failed to update config" }, 500);
    return c.json({ ok: true });
  });

  // Raw TOML endpoints
  app.get("/api/v1/config/raw", (c) => {
    const result = data.readConfigRaw();
    if (!result) return c.json({ error: "config file not found" }, 404);
    return c.json(result);
  });

  app.put("/api/v1/config/raw", async (c) => {
    const { text } = await c.req.json();
    if (typeof text !== "string") return c.json({ error: "text field required" }, 400);
    const result = data.updateConfigRaw(text);
    if ("error" in result) return c.json(result, 422);
    return c.json(result);
  });
}

